# Azure Policy denyAction effect — creates managed deny assignments
# This is the preferred modern mechanism for resource protection

# Example policy: prevent deletion of any resource tagged critical=true
# Policy definition (policy.json)
{
  "mode": "All",
  "policyRule": {
    "if": {
      "field": "tags['critical']",
      "equals": "true"
    },
    "then": {
      "effect": "denyAction",
      "details": {
        "actionNames": [ "delete" ],
        "cascadeBehaviors": { "resourceGroup": "deny" }
      }
    }
  }
}

# Assign the policy
az policy definition create \
    --name 'protect-critical-resources' \
    --rules './policy.json' \
    --mode 'All'

az policy assignment create \
    --name 'protect-critical' \
    --policy 'protect-critical-resources' \
    --scope '/subscriptions/SUB-ID'

# The policy engine creates deny assignments automatically
# on resources that match the condition (tag critical=true)
# Resources gain the deny assignment after the next compliance evaluation cycle

# Diagnosing an unexpected 'AuthorizationFailed' when user has a role

# Step 1: list deny assignments at and above the target scope
$scope = '/subscriptions/SUB/resourceGroups/rg-app'
Get-AzDenyAssignment | Where-Object {
    $scope -like "$($_.Scope)*" -or $_.Scope -eq $scope
} | Select-Object DenyAssignmentName, Scope, @{N='Actions';E={$_.DenyActions.Action}}

# Step 2: check if the principal is in any deny assignment's principal list
$userId = (Get-AzADUser -UserPrincipalName 'alice@contoso.com').Id
Get-AzDenyAssignment | Where-Object {
    $_.Principals.Id -contains $userId -or
    # All-principals deny (created by Blueprints) uses a special token
    $_.Principals.Id -contains '00000000-0000-0000-0000-000000000000'
}

# Step 3: check resource locks
Get-AzResourceLock -ResourceGroupName 'rg-app'

# Step 4: if from a Blueprint, identify which Blueprint assignment created it
Get-AzBlueprintAssignment -SubscriptionId 'SUB-ID' | ForEach-Object {
    [PSCustomObject]@{
        BlueprintName = $_.Name
        LockMode = $_.Locks.Mode
        Scope = $_.Scope
    }
}

# Deny assignment scope and inheritance
# Like role assignments, deny assignments inherit to child scopes
# UNLESS DoNotApplyToChildScopes = true

# Example: deny assignment at subscription scope
# Blocks delete on ALL resource groups and resources in the subscription
Get-AzDenyAssignment -Scope '/subscriptions/SUB-ID' | Where-Object {
    -not $_.DoNotApplyToChildScopes
}

# Check if a specific RG is affected by ANY deny assignment in scope chain
function Get-EffectiveDenyAssignments {
    param([string]$ResourceGroupScope)
    $parts = $ResourceGroupScope -split '/'
    $scopes = @()
    # Build all parent scopes
    for ($i = 2; $i -le $parts.Length; $i += 2) {
        $scopes += ($parts[0..$i] -join '/')
    }
    # Also check management group scopes (if known)
    Get-AzDenyAssignment | Where-Object {
        ($_.Scope -in $scopes -and -not $_.DoNotApplyToChildScopes) -or
        $_.Scope -eq $ResourceGroupScope
    }
}

Get-EffectiveDenyAssignments '/subscriptions/SUB-ID/resourceGroups/rg-protected'

# Audit all deny assignments across an enterprise
$subs = Get-AzSubscription
$allDenies = @()
foreach ($sub in $subs) {
    Set-AzContext -SubscriptionId $sub.Id | Out-Null
    $denies = Get-AzDenyAssignment -ErrorAction SilentlyContinue
    foreach ($d in $denies) {
        $allDenies += [PSCustomObject]@{
            Subscription = $sub.Name
            Name = $d.DenyAssignmentName
            Scope = $d.Scope
            Actions = ($d.DenyActions.Action | Sort-Object) -join '; '
            Principals = ($d.Principals.DisplayName | Sort-Object) -join '; '
            ExcludedPrincipals = ($d.ExcludePrincipals.DisplayName | Sort-Object) -join '; '
            DoNotApplyToChildScopes = $d.DoNotApplyToChildScopes
            CreatedBy = $d.CreatedBy
        }
    }
}
$allDenies | Export-Csv -Path 'deny-assignments-audit.csv' -NoTypeInformation
Write-Host "Total deny assignments: $($allDenies.Count)"

# Summary by type (Blueprint vs Policy vs other)
$allDenies | Group-Object {
    if ($_.Name -like '*blueprint*') { 'Blueprint' }
    elseif ($_.Name -like '*policy*') { 'Policy' }
    else { 'Other' }
} | Select-Object Name, Count
